package com.interview.incidentrca.controller;
import com.fasterxml.jackson.databind.ObjectMapper;import com.interview.incidentrca.dto.*;import com.interview.incidentrca.enums.*;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.http.MediaType;import org.springframework.test.context.ActiveProfiles;import org.springframework.test.web.servlet.MockMvc;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest @AutoConfigureMockMvc @ActiveProfiles("test") class IncidentApiIntegrationTest{@Autowired MockMvc mvc;@Autowired ObjectMapper json; @Test void incidentFlowWorks() throws Exception{String body=mvc.perform(post("/api/auth/login").contentType(MediaType.APPLICATION_JSON).content(json.writeValueAsString(new LoginRequest("admin@incidentrca.dev","Admin@123")))).andExpect(status().isOk()).andReturn().getResponse().getContentAsString();String token=json.readTree(body).get("token").asText();String create=json.writeValueAsString(new IncidentCreateRequest("Database timeout on orders","orders db connection timeout",Severity.HIGH,"Order Service",null));String created=mvc.perform(post("/api/incidents").header("Authorization","Bearer "+token).contentType(MediaType.APPLICATION_JSON).content(create)).andExpect(status().isCreated()).andExpect(jsonPath("$.slaState").exists()).andReturn().getResponse().getContentAsString();long id=json.readTree(created).get("id").asLong();mvc.perform(get("/api/incidents/"+id).header("Authorization","Bearer "+token)).andExpect(status().isOk()).andExpect(jsonPath("$.title").value("Database timeout on orders"));mvc.perform(patch("/api/incidents/"+id+"/status").header("Authorization","Bearer "+token).contentType(MediaType.APPLICATION_JSON).content(json.writeValueAsString(new StatusUpdateRequest(IncidentStatus.INVESTIGATING,"Started triage")))).andExpect(status().isOk()).andExpect(jsonPath("$.status").value("INVESTIGATING"));mvc.perform(post("/api/incidents/"+id+"/comments").header("Authorization","Bearer "+token).contentType(MediaType.APPLICATION_JSON).content(json.writeValueAsString(new CommentRequest("Checking database metrics")))).andExpect(status().isCreated());mvc.perform(get("/api/incidents/"+id+"/timeline").header("Authorization","Bearer "+token)).andExpect(status().isOk()).andExpect(jsonPath("$[0].type").exists());}}
